var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"으음, 역시 총소리만으로는 불협화음이 너무 심하군요.","JPN":"うーん、やはり銃声だけだと不協和音になりますね。","ENG":"Mm, gunshots alone are too dissonant.","TWN":"嗯，光是槍聲就太不和諧了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"그럼 선율을 조금 더 더해볼까요?","JPN":"旋律をもう少し足してみましょうか。","ENG":"Shall I add a little more melody?","TWN":"那麼，要再加入更多的旋律嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"으아……! 으아아……!! 내 몸이 녹아내리고 있어……!! 으아아!!","JPN":"うあ……！　うああ……！！　体が溶け落ちている……！！　うわあ！！","ENG":"Aaah...! AAAGH...!! My body's melting...!! AAAARGH!!","TWN":"我的天啊……！啊……！！我的身體正在融化……！！呃啊啊！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_03"},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"진정해!! 이 총에 총구 들이밀지 마……!!","JPN":"落ち着け！！　銃に銃口を向けるな……！！","ENG":"Calm down! Stop pointing your gun around everywhere...!","TWN":"冷靜點！！別用那把槍指著我……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"열명의인디언이선에서있었다. 한명이집으로걸어가아홉이되었다. 아홉의인디언이문을잡아흔들다가, 한명이떨어져…….","JPN":"10人のインディアンの子が並んでいた。一人が帰って9人になった。9人のインディアンの子が扉を揺すり、一人が落っこちて……","ENG":"Tenlittleindiansstandinginaline. Onetoddledhomeandthentherewerenine. Ninelittleindiansswingingonagate. Onetumbledoffandthen...","TWN":"十個小士兵。一個走回家，十個只剩九。九個小士兵。抓門在搖晃，九個只剩八……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"비명과 통곡이 더해지니. 이제 좀 들을 만하군요.","JPN":"悲鳴と痛哭が加わったら、やっと少しは聞きごたえが出てきましたね。","ENG":"With the added screams and wailing, it is much better.","TWN":"尖叫聲和哀號聲越來越大。這個旋律值得一聽呢。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"이 자리에 저의 악단이 있었다면 좀 더 멋진 연주를 보여드릴 수 있었을 텐데요.","JPN":"ここに私の楽団がいてくれたら、もっと素敵な演奏をお聞かせすることができたのに、残念です。","ENG":"If only my Orchestra was here, we would have been able to put on a spectacular performance.","TWN":"如果我的樂團在這裡，一定能夠為你呈現出更好的演奏。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くうっ……！","ENG":"Kuh...!","TWN":"呃……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후우. 미안하지만, 필요 없거든……?","JPN":"ふう、悪いけど……遠慮するよ。","ENG":"Huu... Sorry, but I'll decline...","TWN":"呼。抱歉，但我不需要……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"정신 나갈 것 같은 소음이나 만들면서, 지휘자를 자청하다니 부끄럽지도 않아?","JPN":"気が狂いそうな騒音しか作り出せないくせに、指揮者を名乗るなんて恥ずかしくないの？","ENG":"Aren't you ashamed to call yourself a conductor when all you do is create noise?","TWN":"只會製造噪音的指揮家，你不覺得這樣很丟人嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"미의 기준이 시대마다 바뀌듯, 당신과 저의 관점이 그만큼 다르다고 할 수 있겠죠.","JPN":"あなたと私の観点が違うのでしょう。時代によって美の基準が変わるのと同じように、ですね。","ENG":"Just as the standard of beauty changes over time, it could be said that you and I merely have different perspectives.","TWN":"正如美麗的標準會隨著時間的推移而變化一樣，可以說你我的觀點並不相同。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"개개인이 받아들이는 예술은 상대적이니까요.","JPN":"一人一人の感じる芸術は主観的なものですから。","ENG":"For art is subjective to each individual.","TWN":"每個人接受的藝術都是相對的。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"의외네? 그림자 주제에 인간 같은 소리를 하잖아?","JPN":"へえ、シャドウのくせに人間みたいなことを言うじゃない。","ENG":"That's surprising. A Shadow is actually making sense like a human being.","TWN":"奇怪？比起暗影你更像個人類。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"잡담을 꺼내시는 것 보니, 슬슬 비책이 다 떨어진 모양이로군요. 환상종의 후예.","JPN":"そんな無駄話を口にするとは……そろそろ秘策も切れたところでしょうか。","ENG":"Seeing how you are making small talk, it seems that you are running out of options, descendant of Bygones.","TWN":"從你閒聊的舉動來看，你似乎已經沒什麼手段了。夢幻品種的後裔。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 이거 들켰나 봐?","JPN":"ふふ、バレた？","ENG":"Fu fuu, you caught me.","TWN":"呵呵，看來被你發現了？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우리 전대원이 둘이나 죽었고, 아르콘 전대에서도 벌써 여럿이 당했어.","JPN":"うちの戦隊員が二人も死んじゃったし、アルコン戦隊も結構な数がやられてしまった。","ENG":"Two members from my division are already dead, and Arkon has already suffered a massive loss.","TWN":"我們戰隊已有兩名成員死亡，阿勒坤戰隊也失去了好幾名隊員。"},"stage":{"bg":"BLACK","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L30_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 외 일반 보병 전력은…… 일일이 숫자를 헤아릴 수 없을 정도야.","JPN":"それ以外に一般歩兵の被害は……数えきれない。","ENG":"For the infantry... There are more than I can count.","TWN":"其餘的普通士兵……數量太多了已經無法統計。"},"stage":{"bg":"BLACK","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"단원들의 서포트가 없는 마에스트로라면 격파가 가능할지도 모른다고 생각했는데…….","JPN":"楽団員のサポートがないマエストロなら撃破できると思ったけど、誤算だったようね……","ENG":"I thought it might be possible to defeat Maestra when she had no support from her members...","TWN":"還以為沒有了團員的協助，就可以擊敗指揮家……"},"stage":{"bg":"BLACK","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"역시 괜히 데모고르곤이라고 부르는 게 아니었네.","JPN":"さすが、デモゴルゴンという名前は伊達じゃないというわけか。","ENG":"But I guess there's a reason she's called the Demogorgon.","TWN":"畢竟，她被稱為魔神也不是沒有道理的。"},"stage":{"bg":"BLACK","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"그럼, 이제 슬슬 막을 내리도록…… ","JPN":"では、そろそろ幕を下ろ…… ","ENG":"Now, it's time to bring it to a close...","TWN":"那麼，讓我們結束吧……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"전 대원! 내 능력으로 마에스트로를 속박시켰다!","JPN":"全隊員！　私の能力でマエストロを束縛した！","ENG":"Everyone! I've bound Maestra with my powers!","TWN":"全體隊員！我用我的能力困住指揮家！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이게 마지막 기회야……!! 모든 화력을 마에스트로에게 집중하도록……!!","JPN":"これが最後のチャンスだ……！！　すべての火力をマエストロに集中させる……！！","ENG":"This is our last chance...! Fire everything you've got on Maestra...!!","TWN":"這是最後的機會……！集中火力攻擊……！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L46_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"제발 좀 죽어라!! 지긋지긋한 마에스트로!!","JPN":"いい加減死ね！！　マエストロめ！！","ENG":"JUST DIE ALREADY!! You damn Maestra!!","TWN":"你去死吧！！該死的指揮家！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"모네카와 연결이 끊어진 기갑 병력은 포신을 고정해서 수동조작으로 쏴 버려!","JPN":"モネカとの通信が切れている機甲兵力は砲身を固定して手動操作で撃て！！","ENG":"Manually position the gun barrel of armored units that are disconnected from Moneka and fire!","TWN":"使用與莫奈卡斷聯的裝甲部隊炮筒，手動進行開火！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"야크샤 부전대장님이 벌어주신 마지막 기회다!","JPN":"ヤクシャー副戦隊長が作ってくれた最後のチャンスだ！","ENG":"This is the last chance Yaksha Deputy Commander has given us!","TWN":"這是夜叉副戰隊長為我們爭取的最後機會！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CRONUS_YAKSHA_NPC_NULL","text":{"KOREA":"기신급 육전병기 2번. 크로노스 프로토 타입, 준비 완료!","JPN":"機神級陸戦兵器第2番、クロノスプロトタイプ、準備完了！","ENG":"God-class ground combat vehicle no. 2, Chronos Prototype, ready!","TWN":"機神級陸戰兵器2號。克羅諾斯原型，準備完畢！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_02"},{"id":"L2_1","type":"dialog","speaker":"CRONUS_YAKSHA_NPC_NULL","text":{"KOREA":"음파에 실린 정보 오염을 감지했다. 대상을 제거한다!","JPN":"音波に乗せられた情報の汚染を感知。対象を排除する！","ENG":"Detecting sound waves with data corruption. Eliminating target!","TWN":"檢測到聲波中攜帶的資訊污染。消滅目標！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CRONUS_YAKSHA_NPC_NULL","text":{"KOREA":"모든 사일로 오픈! 일제 사격 발사!","JPN":"全サイロオープン！　一斉射撃、発射！","ENG":"Open all silos! Volley fire!","TWN":"打開所有筒倉！開始發射！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_MAESTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하아, 하아, 하아……! ","JPN":"はあ、はあ、はあ……！ ","ENG":"*Huff* *Huff* *Huff*","TWN":"哈啊，哈啊，哈啊……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L9_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"부조리할 정도야. 이렇게 화력을 쏟아부었는데 격파가 불가능하다고?","JPN":"こんなの理不尽よ。こんなに火力を注いでも撃破できないの？","ENG":"This is absurd. We poured so much firepower, but she's still standing?","TWN":"不可能吧？我們使用了這麼多火力，不可能失敗吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"으아, 으아아아아악! 쏘지 마! 아아악……!! 쏘지 말라고!! ","JPN":"うあ、うああああああ！　撃つな！　あああ………！！　撃つなああああ！！ ","ENG":"Aaah, AAAAACK! Don't shoot! AAAAGH...! I said, don't shoot!!","TWN":"呃啊，啊啊啊啊！別開槍！啊啊啊……！別開槍！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"살려주세요! 살려주세요! 부전대장님……!!","JPN":"助けてください！　助けてください！　副戦隊長……！！","ENG":"Save me! Save me! Deputy Commander...!!","TWN":"救命！救命！副戰隊長……！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"칭찬을 해드리고 싶은 건 오히려 저랍니다.","JPN":"むしろ私の方こそ、褒めて差し上げたい。","ENG":"I must compliment your efforts.","TWN":"相反，我要稱讚你。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN_02"},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"뭔가를 숨기고 있을지도 모른다고 생각했지만, 인식하기도 전에 얼어붙고 말았네요.","JPN":"何かを隠しているかもしれないと思っていましたが、認識する前に凍り付いてしまいました。","ENG":"I thought you might be hiding something, but I froze even before noticing it.","TWN":"本來以為你在隱瞞什麼，一不留神就被你凍住了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"이미 조상인 환상종의 힘을 어느정도는 사용할 수 있는 모양이로군요.","JPN":"先祖である幻想種の力をある程度は扱えるようですね。","ENG":"It seems that you are able to use a bit of your Bygone ancestors' powers.","TWN":"看來你在某種程度上，已經可以使用原始夢幻品種的力量了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"그들의 후예 중에서도 일부만 다룰 수 있다고 들었는데.","JPN":"彼らの末裔の中でも、極一部のみが扱えるものだと聞きましたが。","ENG":"I heard only a handful of their descendants are able to use it.","TWN":"聽說只有部分後裔才能做到。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"하마터면, 당할 뻔했습니다.","JPN":"あやうく、やられるところでした。","ENG":"So that was a close one.","TWN":"而我差一點就中招。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……들었다고?","JPN":"……聞いた？","ENG":"...You heard?","TWN":"……你聽說過？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그림자 주제에 그걸 어떻게……?","JPN":"シャドウのくせに、それをどうやって……？","ENG":"How could a Shadow know that...?","TWN":"你一個暗影怎麼會聽說……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"크윽, 망할 토끼 같으니라고!","JPN":"くうっ、くそウサギめ！","ENG":"Kgh, you damn rabbit!","TWN":"咳，你這個該死的兔子！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"자기 전대장이 어떻게 되었는지도 모르는 주제에……!","JPN":"自分の戦隊長がどうなっているかも知らないくせに……！","ENG":"And you don't even know what happened to your Commander...!","TWN":"連自己的戰隊長變成什麼樣都不知道……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼, 설마 라이오넬 전대장님께서 정말로 이곳에……?","JPN":"じゃあまさか、ライオネル戦隊長は本当にここに……？","ENG":"Then, Commander Lionel really is here...?","TWN":"那麼，萊諾戰隊長真的在這裡……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"자, 그럼 연주를 끝내보도록 할까요?","JPN":"さて、そろそろ演奏を終わりにしましょうか。","ENG":"Now, shall I end my performance?","TWN":"好了，讓我們結束演奏吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"줄곧 여유로웠던 당신의 비명소리가 궁금하던 참이었으니까요.","JPN":"ずっと余裕あるそぶりのあなたがどんな悲鳴を上げるのか、聞きたくなりました。","ENG":"I am curious to hear you scream after you have been acting so arrogantly.","TWN":"我很好奇，現在強裝鎮定的你馬上會發出怎樣淒美的慘叫。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……크윽!","JPN":"……くっ！","ENG":"...Kgh!","TWN":"……咳咳!"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"연주를 기대하셔도 좋을 거예요.","JPN":"演奏に期待してくださってかまいません。","ENG":"You can look forward to the performance.","TWN":"請期待我的表演。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"제 악단을 망가트린 당신에게는 그만큼 혹독한 벌이 기다리고 있을 테니까.","JPN":"私の楽団を壊したあなたには、相応の罰を与えますから。","ENG":"A harsh punishment awaits you for sabotaging my Orchestra.","TWN":"既然破壞了我的管弦樂隊，那就做好了要接受嚴厲懲罰的準備吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"닥쳐……!!","JPN":"黙れ……！！","ENG":"Shut up...!!","TWN":"閉嘴……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"누가 누구한테 벌을 내린다는 거야!! 이 괴물 자식아……!!","JPN":"誰が誰にお仕置きするってんだ！！　この化け物め……！！","ENG":"Who's punishing whom? You monster...!!","TWN":"誰懲罰誰啊！！你這個怪物……！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"구해주러 왔어, 부전대장.","JPN":"助けに来たぞ、副戦隊長。","ENG":"I'm here to save you, Deputy Commander.","TWN":"我來救你了，副戰隊長。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"앨리스……?","JPN":"アリス……？","ENG":"Alice...?","TWN":"艾莉絲……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"네가 어떻게 여길……?","JPN":"あなたがどうやってここに……？","ENG":"How are you here...?","TWN":"你怎麼會在這裡……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"내가 말했잖아.","JPN":"言っただろう。","ENG":"I told you.","TWN":"我說過的。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"다시는 아무도 내 앞에서 죽게 내버려두지 않겠다고.","JPN":"もう二度と、誰もアタシの目の前で死なせたりしないって。","ENG":"I will not allow anyone to die on my watch anymore.","TWN":"我不會再讓任何人死在我面前。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"너, 그 모습은……?","JPN":"あなた、その姿は……？","ENG":"Hey, isn't that...?","TWN":"你，你身上……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"라이오넬 전대장님의 비스트 클로잖아……?","JPN":"ライオネル戦隊長のビーストクローじゃない……？","ENG":"It's Commander Lionel's Beast Claw, isn't it...?","TWN":"這是萊諾戰隊長的魔獸爪……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"부전대장은 몇 번이나 날 구해줬잖아. 그러니까 이번에는 내 차례야.","JPN":"副戦隊長は何度もアタシを助けてくれたじゃないか。だから、今度はアタシの番だ。","ENG":"You saved my life so many times already. So it's my turn now.","TWN":"副戰隊長救了我好幾次。所以輪到我了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_21"},{"id":"L2_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이제, 내가 너를 구해주겠어. 주디.","JPN":"ここからは、アタシがおまえを助けてやる。ジュディ。","ENG":"Now, I'll save you, Judy.","TWN":"現在，換我來救你。茱蒂。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LIONEL_YAKSHA_NPC_NULL","text":{"KOREA":"내가 너를 이곳으로부터 구해주겠다.","JPN":"私がお前をここから救ってやろう。","ENG":"I'll save you from this place.","TWN":"我會把你從這個地方救出來。"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LIONEL_YAKSHA_NPC_NULL","text":{"KOREA":"그러니 나를 따라오지 않겠나?","JPN":"だから、私について来ないか？","ENG":"So won't you follow me?","TWN":"所以，不來跟著我嗎？"},"stage":{"bg":"SNOWYARD_01","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……그런 거였구나.","JPN":"……そういうことだったのね。","ENG":"...So that's why.","TWN":"……就是這樣的。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"나는 줄곧 너에게서 그 사람을 겹쳐 보고 있었어.","JPN":"私はずっと、あの人とあなたを重ねていた。","ENG":"I kept seeing him when I looked at you all this time.","TWN":"我一直能在你身上看到那個人的影子。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"줄곧 길고양이인 줄 알았는데, 어느덧 사자 흉내 내게 되다니.","JPN":"いつまでも野良猫のままだと思っていたのに、いつの間にか獅子の真似ができるようになったじゃない。","ENG":"I just thought you were a stray cat. But now, you can even mimic a lion.","TWN":"我一直以為的小流浪貓，現在有點獅子樣了呢。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L12_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 많이 컸네? 우리 고양이?","JPN":"ふふ、大きくなったね。","ENG":"Fu fuu, look how much you've grown. Our little kitty.","TWN":"呵呵，長大不少呢？我們的小貓。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐래. 귀만 빼면 내가 너보다 키 크거든?","JPN":"何だよ、耳を除けばアタシのほうが大きいんだからな。","ENG":"Little? You know, I'm taller than you if you don't count your ears.","TWN":"長大？不算耳朵的話，我本來就你高大許多。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"자, 일어서. 같이 싸우는 거야. 부전대장.","JPN":"さ、立て。一緒に戦うぞ。副戦隊長。","ENG":"Now, get up. We fight together, Deputy Commander.","TWN":"現在，站起來。我們一起戰鬥。副戰隊長。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_START_BIG"},{"id":"L16_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"저 그림자를 쓰러트리고 우리가 이 작전을 성공으로 끝내자고.","JPN":"あのシャドウを倒して、この作戦を成功に導くんだ。","ENG":"Let's defeat that Shadow and successfully wrap up this operation.","TWN":"讓我們擊敗那個暗影，成功完成這次作戰吧。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"다카포. 패턴이 반복되는 게 제법 싫증이 나는 군요.","JPN":"ダカーポ。同じパターンが繰り返されて、退屈ですね。","ENG":"Da Capo. I am growing tired of the repeated patterns.","TWN":"從頭再奏。我已經厭倦了重複的模式。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN"},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"그럼, 여기서 피날레로 접어들도록 하죠.","JPN":"ではここでフィナーレに入るとしましょう。","ENG":"Then, let us move on to the finale.","TWN":"現在，讓我們進入終章吧。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};